-- Create "units" table
CREATE TABLE "units" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "code" character varying NOT NULL,
  "name" character varying NOT NULL,
  "precision" bigint NOT NULL DEFAULT 0,
  "is_active" boolean NOT NULL DEFAULT true,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  PRIMARY KEY ("id")
);
-- Create index "unit_code" to table: "units"
CREATE UNIQUE INDEX "unit_code" ON "units" ("code");
-- Create "warehouses" table
CREATE TABLE "warehouses" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "code" character varying NOT NULL,
  "name" character varying NOT NULL,
  "type" character varying NOT NULL,
  "is_active" boolean NOT NULL DEFAULT true,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  PRIMARY KEY ("id")
);
-- Create index "warehouse_code" to table: "warehouses"
CREATE UNIQUE INDEX "warehouse_code" ON "warehouses" ("code");
-- Create index "warehouse_type" to table: "warehouses"
CREATE INDEX "warehouse_type" ON "warehouses" ("type");
-- Create "inventory_balances" table
CREATE TABLE "inventory_balances" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "subject_type" character varying NOT NULL,
  "subject_id" bigint NOT NULL,
  "quantity" numeric(20,6) NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "unit_id" bigint NOT NULL,
  "warehouse_id" bigint NOT NULL,
  PRIMARY KEY ("id"),
  CONSTRAINT "inventory_balances_units_inventory_balances" FOREIGN KEY ("unit_id") REFERENCES "units" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "inventory_balances_warehouses_inventory_balances" FOREIGN KEY ("warehouse_id") REFERENCES "warehouses" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION
);
-- Create index "inventorybalance_subject_type_subject_id_warehouse_id_unit_id" to table: "inventory_balances"
CREATE UNIQUE INDEX "inventorybalance_subject_type_subject_id_warehouse_id_unit_id" ON "inventory_balances" ("subject_type", "subject_id", "warehouse_id", "unit_id");
-- Create "inventory_txns" table
CREATE TABLE "inventory_txns" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "subject_type" character varying NOT NULL,
  "subject_id" bigint NOT NULL,
  "txn_type" character varying NOT NULL,
  "direction" bigint NOT NULL,
  "quantity" numeric(20,6) NOT NULL,
  "source_type" character varying NOT NULL,
  "source_id" bigint NULL,
  "source_line_id" bigint NULL,
  "idempotency_key" character varying NOT NULL,
  "reversal_of_txn_id" bigint NULL,
  "occurred_at" timestamptz NOT NULL,
  "created_at" timestamptz NOT NULL,
  "created_by" bigint NULL,
  "note" character varying NULL,
  "unit_id" bigint NOT NULL,
  "warehouse_id" bigint NOT NULL,
  PRIMARY KEY ("id"),
  CONSTRAINT "inventory_txns_units_inventory_txns" FOREIGN KEY ("unit_id") REFERENCES "units" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "inventory_txns_warehouses_inventory_txns" FOREIGN KEY ("warehouse_id") REFERENCES "warehouses" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION
);
-- Create index "inventorytxn_idempotency_key" to table: "inventory_txns"
CREATE UNIQUE INDEX "inventorytxn_idempotency_key" ON "inventory_txns" ("idempotency_key");
-- Create index "inventorytxn_reversal_of_txn_id" to table: "inventory_txns"
CREATE INDEX "inventorytxn_reversal_of_txn_id" ON "inventory_txns" ("reversal_of_txn_id");
-- Create index "inventorytxn_source_type_source_id_source_line_id" to table: "inventory_txns"
CREATE INDEX "inventorytxn_source_type_source_id_source_line_id" ON "inventory_txns" ("source_type", "source_id", "source_line_id");
-- Create index "inventorytxn_subject_type_subject_id_warehouse_id_occurred_at" to table: "inventory_txns"
CREATE INDEX "inventorytxn_subject_type_subject_id_warehouse_id_occurred_at" ON "inventory_txns" ("subject_type", "subject_id", "warehouse_id", "occurred_at");
-- Create "materials" table
CREATE TABLE "materials" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "code" character varying NOT NULL,
  "name" character varying NOT NULL,
  "category" character varying NULL,
  "spec" character varying NULL,
  "color" character varying NULL,
  "is_active" boolean NOT NULL DEFAULT true,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "default_unit_id" bigint NOT NULL,
  PRIMARY KEY ("id"),
  CONSTRAINT "materials_units_materials" FOREIGN KEY ("default_unit_id") REFERENCES "units" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION
);
-- Create index "material_category" to table: "materials"
CREATE INDEX "material_category" ON "materials" ("category");
-- Create index "material_code" to table: "materials"
CREATE UNIQUE INDEX "material_code" ON "materials" ("code");
-- Create index "material_name" to table: "materials"
CREATE INDEX "material_name" ON "materials" ("name");
-- Create "products" table
CREATE TABLE "products" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "code" character varying NOT NULL,
  "name" character varying NOT NULL,
  "style_no" character varying NULL,
  "customer_style_no" character varying NULL,
  "is_active" boolean NOT NULL DEFAULT true,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "default_unit_id" bigint NOT NULL,
  PRIMARY KEY ("id"),
  CONSTRAINT "products_units_products" FOREIGN KEY ("default_unit_id") REFERENCES "units" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION
);
-- Create index "product_code" to table: "products"
CREATE UNIQUE INDEX "product_code" ON "products" ("code");
-- Create index "product_customer_style_no" to table: "products"
CREATE INDEX "product_customer_style_no" ON "products" ("customer_style_no");
-- Create index "product_name" to table: "products"
CREATE INDEX "product_name" ON "products" ("name");
-- Create index "product_style_no" to table: "products"
CREATE INDEX "product_style_no" ON "products" ("style_no");
